head.script:
scwin.memJson;
scwin.privAdmin;
scwin.strToDate;

scwin.slipNo;
scwin.apprReqNo;

scwin.g_sLoginDept;
scwin.loginId;
scwin.vLoginCoCd;
scwin.vLoginCoClsCd;
scwin.vUserHomeClsCd;
scwin.vCoCd;
scwin.isSubCompany;
scwin.coCd;
scwin.coClsCd;
scwin.vEmpNo;

scwin.comboRtnFlag01;
scwin.comboRtnFlag02;
scwin.interval01;

scwin.onpageload = function() {
	//전역변수값 셋팅함수.
	scwin.initSetVal();

    //전표종류 콤보
    const codeOptions = [{
            method: "getLuxeComboData", 
            param1: "ElectronicApproveEBC", 
            param2: "retrieveSlipKndCdList",
            param3: ["CMP"],         //고정?
            compID: "acb_slipKndCd_H"   //바인딩 할 컴포넌트 id
    }];
    $c.data.setGauceUtil(codeOptions, scwin.commonCodeCallBack01);


    const codeOptions2 = [
        { grpCd: "FI111", compID: "lc_evidClsCd" },  //증빙파일종류 콤보 
        { grpCd: "CO037", compID: "lc_admin1" },  //hidden 콤보
        { grpCd: "FI007", compID: "lc_admin2" },  //hidden 콤보
        { grpCd: "FI627", compID: "lc_change" },  //hidden 콤보
    ];
    $c.data.setCommonCode(codeOptions2, scwin.commonCodeCallBack02);

    scwin.interval01 = setInterval(async function() {
        if(scwin.comboRtnFlag01 == true && scwin.comboRtnFlag02 == true) {
            clearInterval(scwin.interval01);
            //초기화
  	        await scwin.initOnload();
        }
    }, 300);
};

scwin.initSetVal = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.privAdmin = scwin.memJson.privAdmin;
    scwin.strToDate = WebSquare.date.getCurrentServerDate().substring(0, 8);

    scwin.slipNo = $c.data.getParameter("slipNo")  == null ? ""	: $c.data.getParameter("slipNo");
    scwin.apprReqNo = $c.data.getParameter("apprReqNo")  == null ? ""	: $c.data.getParameter("apprReqNo");

    scwin.g_sLoginDept = scwin.memJson.acctDeptCd; 
    scwin.loginId = scwin.memJson.userId; 

    scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd; // 소속 자회사  
    scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd)?'': scwin.memJson.coClsCd;//회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;        // 사용자소속구분코드 
    scwin.vCoCd            = $c.gus.cfIsNull(scwin.memJson.coCd)?'': scwin.memJson.coCd; // 회사코드
    scwin.isSubCompany = false;

    scwin.coCd = "000";
    scwin.coClsCd = "0";
    scwin.vEmpNo = scwin.memJson.empNo;        			// 사번
};

scwin.commonCodeCallBack01 =  function() {
    $p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).insertRow(0);
    $p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).setCellData(0,"code","");
    $p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).setCellData(0,"name","전체");


    ds_combo_slipKndCd.removeAll();
    for(var i=0;i<$p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).getRowCount();i++) {
        var code = $p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).getCellData(i, "code");
        var name = $p.getComponentById(acb_slipKndCd_H.getDataListInfo().id).getCellData(i, "name");

        ds_combo_slipKndCd.insertRow(i);
        ds_combo_slipKndCd.setCellData(i, "cd", code);
        ds_combo_slipKndCd.setCellData(i, "cdNm", name);
        ds_combo_slipKndCd.setCellData(i, "custom", code+"  "+name);
    }

    acb_slipKndCd.getSelectedIndex(0);

    scwin.comboRtnFlag01 = true;
};

scwin.commonCodeCallBack02 = function() {
    let lc_evidClsCd_dataset = $p.getComponentById(lc_evidClsCd.getDataListInfo().id);
    lc_evidClsCd_dataset.sort("cd",0);
    scwin.comboRtnFlag02 = true;
};

scwin.onUdcCompleted = function() {
    ed_coCd.setAllowChar("0-9");
    ed_regId.setAllowChar("0-9");
};

scwin.initOnload = async function() {
    await scwin.f_setCompanyInfo();

    // 초기 조회조건 셋팅
    ed_startDt.setValue(new Date().format("YYYYMMDD").substring(0,6) + "01");
    ed_endDt.setValue(new Date().format("YYYYMMDD").substring(0,8));
    lc_evidClsCd.setValue("00");
    lc_evidFileRegYn.setSelectedIndex(0);
    await scwin.getMaxCloseYm(); //마감년월 가져오기
    var acctDeptCd = scwin.g_sLoginDept;
    var newYear = new Date().format("YYYYMMDD").substring(0,4);


    ed_acctDeptCd.setValue(acctDeptCd);
    if(acctDeptCd != '00009')	//재경팀이 아니면 귀속부서 변경 불가
    {
        if(scwin.vEmpNo == "198015" || scwin.vEmpNo == "198078") {//BIDC 이재설 과장, 최현주 대리 추가 (박경진대리 퇴사로 최현주 대리 변경)

        }else {
            var admin = "";
            var bizdiv = "";

            /*
            ds_admin.SyncLoad = true;
            ds_admin.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=CO037&cd=&cdNm=";
            ds_admin.Reset();
            */

            await scwin.getAcctDeptCd(newYear, acctDeptCd);

            for(var i=0; i< $p.getComponentById(lc_admin1.getDataListInfo().id).getRowCount(); i++){
                for(var j=0; j< ds_bizdiv.getRowCount(); j++)
                {
                    admin = $p.getComponentById(lc_admin1.getDataListInfo().id).getCellData(i,"cd");
                    bizdiv = ds_bizdiv.getCellData(j,"col2");
                    if(admin == bizdiv)
                    {
                        ed_acctDeptCd.setValue(admin);	
                    }
                    break;
                }
            }	

            if((scwin.loginId == '072924') || (scwin.loginId == '130412'))	//중부지사 사람들 2명
            {
                ed_acctDeptCd.setValue('00751');	
            }	

            if((scwin.loginId == '080928') || (scwin.loginId == '102078'))	//대중관리 사람들 2명
            {
                ed_acctDeptCd.setValue('00100');	
            }

            //회사코드 변경불가
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);

            scwin.f_changeCheck(); //작성부서 변경 권한 체크 
        }
    }
    else	// 재경팀 이면 작성부서 00009로 셋팅 하고 얘네들은 수정 가능
    {
        ed_acctDeptCd.setValue(scwin.g_sLoginDept);
    }
};

//-------------------------------------------------------------------------
// 전월 마감여부 
//-------------------------------------------------------------------------
scwin.getMaxCloseYm = async function() {
    dma_search2.set("coCd", scwin.vCoCd);

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_getMaxCloseYm);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_getMaxCloseYm_submitdone();
    }
};

scwin.sbm_getMaxCloseYm_submitdone = async function (e) {
    var thisYm = scwin.strToDate; // 오늘일자 가져오기
	//최소 미마감월이 당월이 아닐때
	if(ds_getMaxCloseYm.getCellData(0,"closeYm") != thisYm.substr(0,6)){ 
		var closeYm = ds_getMaxCloseYm.getCellData(0,"closeYm");
		var firstDay = closeYm.substr(0,4)+"/"+closeYm.substr(4,2)+"/"+"01";  // 1일
		var lastDay =  closeYm.substr(0,4)+"/"+closeYm.substr(4,2)+"/" + new Date(closeYm.substr(0,4),closeYm.substr(4,2),0).getDate(); // 마지막날
		ed_endDt.setValue(lastDay); //작성일자 셋팅
		ed_startDt.setValue(firstDay);
	}else{
		var firstDay = thisYm.substr(0,4)+"/"+thisYm.substr(4,2)+"/"+"01";  //당월 1일
		var lastDay = thisYm.substr(0,4)+"/"+thisYm.substr(4,2)+"/"+ new Date(thisYm.substr(0,4),thisYm.substr(4,2),0).getDate(); //당월 마지막날
		ed_endDt.setValue(lastDay); //작성일자 셋팅
		ed_startDt.setValue(firstDay);
	}
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = async function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU ;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.coCd = scwin.vLoginCoCd;
    scwin.coClsCd = scwin.vLoginCoClsCd;
    await scwin.f_PopUpCompanyInfo('T'); 

    if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) {  // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
    }else {
        $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);   
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_company.setSelectId("retrieveDongbuGroupCompanyInfo");
    await udc_company.cfCommonPopUp(scwin.udc_company_callBackFunc
								,ed_coCd.getValue(), ed_coNm.getValue()
								,pWinCloseTF,null,null,null,null
								,null,null,null,null,null);   
};

scwin.udc_company_callBackFunc = function (rtnList) {
    // SET	 
    if(rtnList != null ) { 
        if (rtnList[0] == "N/A") {
            return;
        }  

        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        tbx_CoClsCd.setValue(rtnList[1]);	// 회사구분  
        scwin.coCd = ed_coCd.getValue(); 
        scwin.coClsCd = rtnList[1];	// 회사구분    
    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        tbx_CoClsCd.setValue("");
        scwin.coCd = ""; 
        scwin.coClsCd = "";
    }


    if(Number(tbx_CoClsCd.getValue()) > Number(ACConstants.CO_CLS_CD_DONGBU))  {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    }
};

//-------------------------------------------------------------------------
// 작성부서 변경 권한 체크 
//-------------------------------------------------------------------------
scwin.f_changeCheck = function() {
    var userId = scwin.loginId;
    var empNo = scwin.vEmpNo;
    var acctDeptCd = scwin.g_sLoginDept;

    var admin = "";

    var count1 = 0;
    /*    
    ds_change.SyncLoad = true;
    ds_change.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=FI627&cd=&cdNm=";
    ds_change.Reset();
    */

    let dataset = $p.getComponentById(lc_change.getDataListInfo().id);
    for(var i=0; i< dataset.getRowCount(); i++){
        var partAdmin = dataset.getCellData(i,"cd");
        if(empNo == partAdmin){
            count1++;	
        }
    }   	

    if(count1 == '0'){
        $c.gus.cfDisableObjects([ed_acctDeptCd, ed_acctDeptNm, btn_acctDept]);	
    }else{
        $c.gus.cfEnableObjects([ed_acctDeptCd, ed_acctDeptNm, btn_acctDept]);	
    }
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    var empNo = scwin.vEmpNo;
    var acctDeptCd = scwin.g_sLoginDept;
    var newYear = new Date().format("YYYYMMDD").substring(0,4);

    ed_startDt.setValue(ed_startDt.getValue().replace(/\//gi, ''));
    ed_endDt.setValue(ed_endDt.getValue().replace(/\//gi, ''));

    if(ed_startDt.getValue() == "" || ed_endDt.getValue() == "")
    {
        await $c.win.alert("작성일자는 필수입력조건 입니다.");
        if(ed_startDt.getValue() == "")
        {
            ed_startDt.focus();
        }
        else
        {
            ed_endDt.focus();
        }
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_startDt.getValue(), ed_endDt.getValue()))
    {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    if(acctDeptCd != '00009' && ed_acctDeptCd.getValue() == "")
    {
        if(scwin.vEmpNo == "198015" || scwin.vEmpNo == "198078") {//BIDC 이재설 과장, 최현주 대리 추가 (박경진대리 퇴사로 최현주 대리 변경)
        }else {
            await $c.win.alert("작성부서는 필수입력조건 입니다.");
            ed_acctDeptCd.focus();
            return;
        }
    }

    if(ibx_slipNo.getValue() != "" && ibx_slipNo.getValue().length < 10)
    {
        await $c.win.alert("전표번호를 올바르게 입력 하세요.\n(전표번호는 10자리 입니다.)");
        ibx_slipNo.focus();
        return;
    }

    await scwin.getAcctDeptCd(newYear, acctDeptCd);

    var admin = "";
    var bizdiv = "";
    var count1 = 0;
    var count2 = 0;

    /*    
    ds_admin.SyncLoad = true;
    ds_admin.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=FI007&cd=&cdNm=";
    ds_admin.Reset();
    */
    let dataset = $p.getComponentById(lc_admin2.getDataListInfo().id);

    for(var i=0; i< dataset.getRowCount(); i++){
        admin = dataset.getCellData(i,"cd");
        if(empNo == admin){
            count1++;	
        }
    }   	

    for(var i=0; i< ds_bizdiv.getRowCount(); i++){
        bizdiv = ds_bizdiv.getCellData(i,"col2");
        if(acctDeptCd == bizdiv){
            count2++;
        }
    }

    if((count1 == 0) && (count2 == 0))
    {
        await $c.win.alert("조회권한이 없습니다.\n\n조회권한 : 재경팀, 지사 관리팀");
        return;
    }

    /*
    ds_search.UseChangeInfo = false;			 
    tr_search.Action="/ac.fi.taxbiz.evidmgnt.RetrieveFileEvidClsCdCMD.do";
    tr_search.post();
    */

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_search);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search_submitdone();
    }
};

scwin.sbm_search_submitdone = async function (e) {
    tbx_totalRows.setValue(ds_evid.getRowCount());

    if(ds_evid.getRowCount() == 0)
    {
        await $c.win.alert("조회 결과가 존재하지 않습니다.");
        return;
    }
};

//-------------------------------------------------------------------------
// 권한관련 귀속부서 조회
//-------------------------------------------------------------------------
scwin.getAcctDeptCd = async function(newYear, acctDeptCd) {
    // SELECT 절 
    var param1 = 
            " ACCT_DEPT_CD   as COL1 "
        + ",ACCT_DEPT_CD   as COL2 "
        + ",''   		as COL3 "
        + ",''   		as COL4 "
        + ",''  		as COL5 "
        + ",'' 			as COL6 "
        + ",'' 			as COL7 "
        + ",'' 			as COL8 "
        + ",'' 			as COL9 "
        + ",'' 			as COL10 "
        ;

    // 대상테이블 	
    var param2 = 			
            "(SELECT * FROM TB_CO011 WHERE ACCT_YEAR = SUBSTR('" + newYear + "',1,4))"
        + "  START  WITH ACCT_DEPT_CD = ( "
        + "                                 SELECT UPPER_ACCT_DEPT_CD "
        + "                                   FROM TB_CO011 "
        + "                                  WHERE ACCT_YEAR = SUBSTR('" + newYear + "',1,4)"
        + "                                    AND ACCT_DEPT_CD = '" + acctDeptCd + "'"	
        + "							 ) "
        + "  CONNECT BY PRIOR ACCT_DEPT_CD = UPPER_ACCT_DEPT_CD "
        ;

    // 조건절	  
    //var param3 = 						  
    //	   " AND 1=1 "
        ;

    // 정렬    
    var param4 = 	
            " ACCT_DEPT_CD "

    /*        
    ds_bizdiv.DataId = 
        "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest3" + "&param1=" + param1 
                                                                                    + "&param2=" + param2
                                                                                    + "&param4=" + param4;		
    ds_bizdiv.Reset();
    */

    dma_bizdiv.set("sysCd", "CommonEBC");
    dma_bizdiv.set("queryId", "dinymicQueryTest3");
    dma_bizdiv.set("param1", param1);
    dma_bizdiv.set("param2", param2);
    dma_bizdiv.set("param4", param4);

    ds_bizdiv.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_bizdiv);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_bizdiv_submitdone();
    }
};

scwin.sbm_bizdiv_submitdone = async function (e) {
};

//-------------------------------------------------------------------------
// function name : f_OpenCommonPopUp
// function desc : 귀속부서팝업
//-------------------------------------------------------------------------
scwin.f_OpenCommonPopUp  = async function (callObj, gubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var pSelectID 		= "";
    var pWtitleSearch 	= null;
    var param = ","+ed_coCd.getValue()+",,0";  

    if(gubun == 4){ //부서
        pSelectID 	  = "retrieveAcctDeptCdInfo6";
        pWtitleSearch = null;		
    }
    callObj.setSelectId(pSelectID);
    scwin.udc_objNm = "udc_acctDept";
    await callObj.cfCommonPopUp( scwin.udc_AllInOne_callBackFunc	
                                ,pCode					// 화면에서의 ??? Code Element의	Value
                                ,pName					// 화면에서의 ??? Name Element의	Value
                                ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null					// Title순서	
                                ,null					// 보여주는 각 컬럼들의 폭	
                                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                ,param					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                ,null					// 윈도우 위치 Y좌표	
                                ,null					// 윈도우 위치 X좌표
                                ,null					// 중복체크여부	("F")
                                ,pAllSearch				// 전체검색허용여부	("F")
                                ,pWtitleSearch			// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );
};

scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "udc_acctDept") {
        codeObj = ed_acctDeptCd;
        nameObj = ed_acctDeptNm;
    }

    $c.gus.cfSetReturnValue(rtnList, codeObj, nameObj);
};

scwin.f_ChkOpenCommonPopUp  = async function (callObj, gubun, inObj, pairObj, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == undefined || isCode == true) {
	    await scwin.f_OpenCommonPopUp(callObj, gubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
    else {
	    await scwin.f_OpenCommonPopUp(callObj, gubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// function name : f_SearchPopUp
// function desc : 조회 팝업
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_SearchPopUp = async function (flag,check,isCdYn) {
    switch (flag) {	    
        case '2':
        // 사번
        var param = ""+scwin.coCd;
        udc_regEmp.setSelectId("retrieveAcEmpInfo");
        await udc_regEmp.cfCommonPopUp(scwin.udc_regEmp_callBackFunc,ed_regId.getValue().trim(),ed_empNm.getValue(),check,null,null,null,null,param,null,null,null,null); 

        break;		
    }
};

scwin.udc_regEmp_callBackFunc = function (rtnList) {
    scwin.f_resultPopEd(ed_regId,ed_empNm,rtnList);
};

//-------------------------------------------------------------------------
// function name : f_resultPopEd
// function desc : 팝업결과 셋팅
// function Parameter : strCd : 코드, strNm : 코드명, rtnList : 결과 리스트
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd,strNm,rtnList) {
    if (rtnList != null ) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]);	// 코드
        strNm.setValue(rtnList[1]);	// 명
    } else {
        strCd.setValue("");
        strNm.setValue("");
    }
};


//-------------------------------------------------------------------------
// function name : f_userToExcel()
// function desc : 엑셀저장
// function Parameter : gr_groupCode : 그리드명, gridName : 엑셀저장명
//-------------------------------------------------------------------------
scwin.f_userToExcel = async function (gr_evid, gridName) {
    if (ds_evid.getRowCount() <= 0)
    {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_009,Array("데이타"));  // 출력할 @이(가) 없습니다.
        return false;
    }
    //cfGridToExcel(gr_evid, gridName,"C:\\" + gridName + ".xls", 4+8+16);
    const options = {
        fileName: gridName+".xlsx",
        sheetName : gridName,
        type:1,
        footerColor: '#D4DAE2',
        useStyle:true
    };
    $c.data.downloadGridViewExcel(gr_evid, options);
};


