scwin.gr_evid_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo") {

		//cfShowSlipInfo(ds_evid.NameValue(Row,"slipNo"));
        let slipNo = ds_evid.getCellData(rowIndex,"slipNo");
        let result = await $c.gus.cfShowSlipInfo(slipNo);
    }
